import{bV as a,aL as n,u as e,G as i}from"./chunks/framework.BfzMay2U.js";const b=JSON.parse('{"title":"Ghostty 美化","description":"","frontmatter":{"title":"Ghostty 美化","date":"2026-07-05T00:00:00.000Z"},"headers":[],"relativePath":"ai/terminal/ghostty.md","filePath":"ai/terminal/ghostty.md"}'),t={name:"ai/terminal/ghostty.md"};function p(l,s,h,r,o,c){return n(),e("div",null,[...s[0]||(s[0]=[i(`<h1 id="ghostty-美化" tabindex="-1">Ghostty 美化 <a class="header-anchor" href="#ghostty-美化" aria-label="Permalink to &quot;Ghostty 美化&quot;">​</a></h1><blockquote><p>MacOS 版本</p></blockquote><h2 id="ghostty-的主题配置" tabindex="-1">ghostty 的主题配置 <a class="header-anchor" href="#ghostty-的主题配置" aria-label="Permalink to &quot;ghostty 的主题配置&quot;">​</a></h2><p><a href="https://github.com/catppuccin/ghostty" target="_blank" rel="noreferrer">https://github.com/catppuccin/ghostty</a></p><ul><li>下载下来，放到<code>~/.config/ghostty/themes/</code>下</li><li>打开<code>ghostty</code>的设置，进行编辑配置</li></ul><p>主要配置如下</p><blockquote><p>前提你得下载安装一些<code>Nerd Font</code>的字体</p><p><a href="https://www.nerdfonts.com/font-downloads" target="_blank" rel="noreferrer">https://www.nerdfonts.com/font-downloads</a></p></blockquote><div class="language-txt vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># --- Typography ---</span></span>
<span class="line"><span>font-family = &quot;0xProto Nerd Font Mono Bold&quot;</span></span>
<span class="line"><span>font-size = 16</span></span>
<span class="line"><span>adjust-cell-height = 2</span></span>
<span class="line"><span></span></span>
<span class="line"><span># --- Theme and Colors ---</span></span>
<span class="line"><span>theme = Catppuccin Mocha</span></span>
<span class="line"><span>mouse-hide-while-typing = true</span></span>
<span class="line"><span></span></span>
<span class="line"><span>window-padding-x = 12</span></span>
<span class="line"><span>window-padding-y = 12</span></span>
<span class="line"><span>window-padding-balance = true</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><p>需要保存配置后重启<code>ghostty</code></p><h2 id="安装starship-彩虹状态栏" tabindex="-1">安装starship 彩虹状态栏 <a class="header-anchor" href="#安装starship-彩虹状态栏" aria-label="Permalink to &quot;安装starship 彩虹状态栏&quot;">​</a></h2><blockquote><p>注意了，如果你已经安装了<code>oh-my-zsh</code>之类的，那就别弄这个了，基本上就是美化效果。</p></blockquote><p>官网地址：<a href="https://starship.rs/zh-CN/" target="_blank" rel="noreferrer">https://starship.rs/zh-CN/</a></p><p>使用<code>homebrew</code>安装</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> starship</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>使用<code>winget</code>安装</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">winget</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> starship</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="配置初始化脚本" tabindex="-1">配置初始化脚本 <a class="header-anchor" href="#配置初始化脚本" aria-label="Permalink to &quot;配置初始化脚本&quot;">​</a></h3><h4 id="zsh配置" tabindex="-1">zsh配置 <a class="header-anchor" href="#zsh配置" aria-label="Permalink to &quot;zsh配置&quot;">​</a></h4><p>在<code>~/.zshrc</code>文件末尾添加以下内容</p><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ~/.zshrc</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">eval</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">starship</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init zsh)&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h4 id="bash-配置" tabindex="-1">bash 配置 <a class="header-anchor" href="#bash-配置" aria-label="Permalink to &quot;bash 配置&quot;">​</a></h4><p>在<code>~/.bashrc</code>文件末尾添加以下内容</p><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ~/.bashrc</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">eval</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">starship</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init bash)&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><blockquote><p>其他的可以按照官网的配置步骤来，我主要使用的还是<code>zsh</code></p></blockquote><p>配置完成之后，重启终端。</p><h3 id="配置和-catppuccin-的预设配置" tabindex="-1">配置和 Catppuccin 的预设配置 <a class="header-anchor" href="#配置和-catppuccin-的预设配置" aria-label="Permalink to &quot;配置和 Catppuccin 的预设配置&quot;">​</a></h3><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">starship</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> preset</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> catppuccin-powerline</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.config/starship.toml</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果提示写入有问题，会提示你加上<code>--force</code>，在上述命令后面加上这个即可。</p><p><img src="https://virusoss.oss-cn-shanghai.aliyuncs.com/image-20260705174124576.png" alt="image-20260705174124576" loading="lazy"></p>`,29)])])}const u=a(t,[["render",p]]);export{b as __pageData,u as default};
